using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Default discriminator property renamed from
        // "Discriminator" to "$type" in EF Core 9. Existing documents still
        // store "Discriminator", so we must keep the old name.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: Default id format changed from
        // "{Discriminator}|{Key}" to just "{Key}". Existing documents use
        // the old format, so we preserve it with a custom value generator.
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasValueGeneratorFactory<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.Internal.IdValueGeneratorFactory>();

        // Breaking change 3: HasIndex() now throws for Cosmos (it was
        // silently ignored in EF Core 8). Removed the unsupported call.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

